static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dReluBiasAddCustomTilingData tiling;

    const gert::Shape* x_shape = context->GetInputShape(0);
    const gert::Shape* w_shape = context->GetInputShape(1);
    if (x_shape == nullptr || w_shape == nullptr) {
        return ge::GRAPH_FAILED;
    }

    // x: [N, Cin, H, W], weight: [Cout, Cin, Kh, Kw]
    const auto& x_dims = x_shape->GetStorageShape();
    const auto& w_dims = w_shape->GetStorageShape();
    if (x_dims.GetDimNum() != 4 || w_dims.GetDimNum() != 4) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N  = static_cast<uint32_t>(x_dims.GetDim(0));
    const uint32_t Ci = static_cast<uint32_t>(x_dims.GetDim(1));
    const uint32_t H  = static_cast<uint32_t>(x_dims.GetDim(2));
    const uint32_t W  = static_cast<uint32_t>(x_dims.GetDim(3));

    const uint32_t Co = static_cast<uint32_t>(w_dims.GetDim(0));
    const uint32_t Ci_w = static_cast<uint32_t>(w_dims.GetDim(1));
    const uint32_t Kh = static_cast<uint32_t>(w_dims.GetDim(2));
    const uint32_t Kw = static_cast<uint32_t>(w_dims.GetDim(3));

    if (Ci != Ci_w) {
        return ge::GRAPH_FAILED;
    }
    if (H < Kh || W < Kw) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t Hout = H - Kh + 1;
    const uint32_t Wout = W - Kw + 1;

    // Optional conv bias present?
    bool hasConvBias = (context->GetInputTensor(2) != nullptr);

    // Simple tiling: 1 output element per iteration
    const uint32_t tileOut = 1;

    // Determine blockDim based on total output size
    const uint64_t totalOut = static_cast<uint64_t>(N) * Co * Hout * Wout;
    uint32_t blockDim = static_cast<uint32_t>(totalOut);
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u; // conservative upper bound for stability

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cin(Ci);
    tiling.set_cout(Co);
    tiling.set_h(H);
    tiling.set_w(W);
    tiling.set_kh(Kh);
    tiling.set_kw(Kw);
    tiling.set_hout(Hout);
    tiling.set_wout(Wout);
    tiling.set_tileOut(tileOut);
    tiling.set_blockDim(blockDim);
    tiling.set_hasConvBias(hasConvBias ? 1u : 0u);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaces = context->GetWorkspaceSizes(1);
    workspaces[0] = 0; // no workspace
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {

static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0); // [N,Cin,H,W]
    const gert::Shape *w_shape = context->GetInputShape(1); // [Cout,Cin,Kh,Kw]
    if (x_shape == nullptr || w_shape == nullptr) {
        return GRAPH_FAILED;
    }
    auto xs = x_shape->GetOriginShape();
    auto ws = w_shape->GetOriginShape();
    if (xs.GetDimNum() != 4 || ws.GetDimNum() != 4) {
        return GRAPH_FAILED;
    }

    int64_t N = xs.GetDim(0);
    int64_t Cin = xs.GetDim(1);
    int64_t H = xs.GetDim(2);
    int64_t W = xs.GetDim(3);

    int64_t Cout = ws.GetDim(0);
    int64_t Cin_w = ws.GetDim(1);
    int64_t Kh = ws.GetDim(2);
    int64_t Kw = ws.GetDim(3);

    if (Cin != Cin_w) return GRAPH_FAILED;
    if (H < Kh || W < Kw) return GRAPH_FAILED;

    int64_t Hout = H - Kh + 1;
    int64_t Wout = W - Kw + 1;

    gert::Shape *y_shape = context->GetOutputShape(0);
    gert::Shape out;
    out.SetDimNum(4);
    out.SetDim(0, N);
    out.SetDim(1, Cout);
    out.SetDim(2, Hout);
    out.SetDim(3, Wout);
    *y_shape = out;
    return GRAPH_SUCCESS;
}

