#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

static at::Tensor conv2d_relu_bias_add_impl_npu(const at::Tensor& x,
                                                const at::Tensor& weight,
                                                const c10::optional<at::Tensor>& conv_bias_opt,
                                                const at::Tensor& post_bias) {
    at::Tensor y;
    // Allocate output based on inferred shape on NPU side; we can allocate empty_like with resized sizes
    // Let ACL infer shape; use empty tensor as placeholder
    y = at::empty({0}, x.options());

    if (conv_bias_opt.has_value() && conv_bias_opt.value().defined()) {
        const at::Tensor& conv_bias = conv_bias_opt.value();
        EXEC_NPU_CMD(aclnnConv2dReluBiasAddCustom, x, weight, conv_bias, post_bias, y);
    } else {
        // Pass an undefined tensor for optional bias
        at::Tensor empty_bias;
        EXEC_NPU_CMD(aclnnConv2dReluBiasAddCustom, x, weight, empty_bias, post_bias, y);
    }
    return y;
}

